CREATE TYPE "ActivityType" AS ENUM ('FOLLOW','SUBSCRIBE','RENEWAL','COMMUNITY_POST','STREAM_STARTED','STREAM_ENDED','OTHER');
CREATE TYPE "InsightKind" AS ENUM ('CREATOR_BRIEF','PRIORITY','GROWTH');
CREATE TABLE "users" ("id" TEXT PRIMARY KEY,"blazeUserId" TEXT NOT NULL UNIQUE,"displayName" TEXT NOT NULL,"avatarUrl" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "channels" ("id" TEXT PRIMARY KEY,"userId" TEXT NOT NULL,"blazeChannelId" TEXT NOT NULL UNIQUE,"displayName" TEXT NOT NULL,"avatarUrl" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "channels_userId_fkey" FOREIGN KEY ("userId") REFERENCES "users"("id") ON DELETE CASCADE);
CREATE TABLE "channel_credentials" ("id" TEXT PRIMARY KEY,"channelId" TEXT NOT NULL UNIQUE,"encryptedAccessToken" TEXT NOT NULL,"encryptedRefreshToken" TEXT,"tokenExpiresAt" TIMESTAMP(3),"scopes" TEXT[] NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "channel_credentials_channelId_fkey" FOREIGN KEY ("channelId") REFERENCES "channels"("id") ON DELETE CASCADE);
CREATE TABLE "sessions" ("id" TEXT PRIMARY KEY,"userId" TEXT NOT NULL,"tokenHash" TEXT NOT NULL UNIQUE,"expiresAt" TIMESTAMP(3) NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "sessions_userId_fkey" FOREIGN KEY ("userId") REFERENCES "users"("id") ON DELETE CASCADE);
CREATE TABLE "oauth_states" ("id" TEXT PRIMARY KEY,"stateHash" TEXT NOT NULL UNIQUE,"codeVerifier" TEXT,"returnTo" TEXT,"expiresAt" TIMESTAMP(3) NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "channel_stats_snapshots" ("id" TEXT PRIMARY KEY,"channelId" TEXT NOT NULL,"viewerCount" INTEGER NOT NULL,"isLive" BOOLEAN NOT NULL,"streamTitle" TEXT,"streamCategory" TEXT,"streamStartedAt" TIMESTAMP(3),"capturedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "channel_stats_snapshots_channelId_fkey" FOREIGN KEY ("channelId") REFERENCES "channels"("id") ON DELETE CASCADE);
CREATE TABLE "followers_snapshots" ("id" TEXT PRIMARY KEY,"channelId" TEXT NOT NULL,"count" INTEGER NOT NULL,"capturedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "followers_snapshots_channelId_fkey" FOREIGN KEY ("channelId") REFERENCES "channels"("id") ON DELETE CASCADE);
CREATE TABLE "subscriber_snapshots" ("id" TEXT PRIMARY KEY,"channelId" TEXT NOT NULL,"count" INTEGER NOT NULL,"capturedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "subscriber_snapshots_channelId_fkey" FOREIGN KEY ("channelId") REFERENCES "channels"("id") ON DELETE CASCADE);
CREATE TABLE "activities" ("id" TEXT PRIMARY KEY,"channelId" TEXT NOT NULL,"blazeActivityId" TEXT UNIQUE,"type" "ActivityType" NOT NULL,"actorId" TEXT,"actorName" TEXT,"label" TEXT NOT NULL,"payload" JSONB,"occurredAt" TIMESTAMP(3) NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "activities_channelId_fkey" FOREIGN KEY ("channelId") REFERENCES "channels"("id") ON DELETE CASCADE);
CREATE TABLE "health_scores" ("id" TEXT PRIMARY KEY,"channelId" TEXT NOT NULL,"score" INTEGER NOT NULL,"grade" TEXT NOT NULL,"contributors" JSONB NOT NULL,"insight" TEXT NOT NULL,"calculatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "health_scores_channelId_fkey" FOREIGN KEY ("channelId") REFERENCES "channels"("id") ON DELETE CASCADE);
CREATE TABLE "insights" ("id" TEXT PRIMARY KEY,"channelId" TEXT NOT NULL,"kind" "InsightKind" NOT NULL,"title" TEXT NOT NULL,"body" TEXT NOT NULL,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"expiresAt" TIMESTAMP(3),CONSTRAINT "insights_channelId_fkey" FOREIGN KEY ("channelId") REFERENCES "channels"("id") ON DELETE CASCADE);
CREATE INDEX "channels_userId_idx" ON "channels"("userId");
CREATE INDEX "sessions_userId_expiresAt_idx" ON "sessions"("userId","expiresAt");
CREATE INDEX "channel_stats_snapshots_channelId_capturedAt_idx" ON "channel_stats_snapshots"("channelId","capturedAt");
CREATE INDEX "followers_snapshots_channelId_capturedAt_idx" ON "followers_snapshots"("channelId","capturedAt");
CREATE INDEX "subscriber_snapshots_channelId_capturedAt_idx" ON "subscriber_snapshots"("channelId","capturedAt");
CREATE INDEX "activities_channelId_occurredAt_idx" ON "activities"("channelId","occurredAt");
CREATE INDEX "health_scores_channelId_calculatedAt_idx" ON "health_scores"("channelId","calculatedAt");
CREATE INDEX "insights_channelId_kind_createdAt_idx" ON "insights"("channelId","kind","createdAt");
